import{_ as a,c as t,o as e,aj as o}from"./chunks/framework.CLcCQpUA.js";const u=JSON.parse('{"title":"📒 额外使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"faq/extra.md","filePath":"faq/extra.md"}'),i={name:"faq/extra.md"},c=o('<h1 id="📒-额外使用说明" tabindex="-1">📒 额外使用说明 <a class="header-anchor" href="#📒-额外使用说明" aria-label="Permalink to &quot;📒 额外使用说明&quot;">​</a></h1><h2 id="_1-域名相关" tabindex="-1">1. 域名相关 <a class="header-anchor" href="#_1-域名相关" aria-label="Permalink to &quot;1. 域名相关&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">简化流程的方法 &gt; <a href="/ComicGUISpider/feat/#_4-2-域名工具-domaintool">域名工具</a></p></div><p>各网站的 <code>发布页</code>/<code>永久链接</code> 能在 <code>scripts/utils/website/__init__.py</code> 里找到<br> （国内域名专用）域名缓存文件为 <code>scripts/__temp/xxx_domain.txt</code>（xxx = <code>wnacg</code>或<code>jm</code>），<br> 缓存有效期为 48 小时<br> 程序每次启动会检测是否处于有效期内，过期或网络问题会删除缓存，下次启动重新获取<br> 处于有效期内则可对此文件删改换域名等或加个空格保存即时生效</p><div class="tip custom-block"><p class="custom-block-title">手动改域名缓存文件示例</p><p><code>scripts/__temp/wnacg_domain.txt</code>，没有则自建，内容填个 <code>www.wn01.uk</code> 即可</p></div><div class="info custom-block"><p class="custom-block-title"><code>发布页</code>/<code>永久链接</code>失效的情况下鼓励用户向开发者提供新可用网址，让软件能够持续使用</p></div><h2 id="_2-配置生效相关" tabindex="-1">2. 配置生效相关 <a class="header-anchor" href="#_2-配置生效相关" aria-label="Permalink to &quot;2. 配置生效相关&quot;">​</a></h2><p>除少部分条目例如预设(只影响gui)，能当即保存时立即生效(保存配置的操作与gui同一进程);<br> 其余影响后台进程的配置条目在选择网站后定型(点选网站后<code>后台进程</code>即开始)，<br> 如果选网站后才反应过来改配置，需重启CGS方可生效</p><h2 id="_3-配置系文件路径" tabindex="-1">3. 配置系文件路径 <a class="header-anchor" href="#_3-配置系文件路径" aria-label="Permalink to &quot;3. 配置系文件路径&quot;">​</a></h2><p>执行如下命令查看</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;from pathlib import Path;from PyQt5.QtCore import QStandardPaths;print(Path(QStandardPaths.writableLocation(QStandardPaths.AppConfigLocation)).joinpath(&#39;CGS&#39;))&quot;</span></span></code></pre></div><p>此路径设有文件如下:</p><ul><li><code>conf.yml</code>: 配置文件</li><li><code>reccord.db</code>: 去重记录</li></ul>',13),s=[c];function d(r,l,n,p,h,_){return e(),t("div",null,s)}const b=a(i,[["render",d]]);export{u as __pageData,b as default};
